  // } else if (p.login_type === 'google') {
  //   p.appid = client_id.google
  // } else if (p.login_type === 'facebook') {
  //   p.appid = client_id.facebook
  // }
  const ticket = encodeURIComponent(JSON.stringify(p))
  location.href = `sawaludo://sawaksa_login_key?ticket=${ticket}`
